 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→void riscv_nn_conv_HWC_s8_s8_s8_sym_bias_any(const q7_t * in_tensor,
 26→                            const uint16_t in_tensor_dim_x,
 27→                            const uint16_t in_tensor_dim_y,
 28→                            const uint16_t in_tensor_ch,
 29→                            const q7_t * ker_weight,
 30→                            const uint16_t out_tensor_ch,
 31→                            const uint16_t ker_dim_x,
 32→                            const uint16_t ker_dim_y,
 33→                            const uint16_t pad_x,
 34→                            const uint16_t pad_y,
 35→                            const uint16_t stride_x,
 36→                            const uint16_t stride_y,
 37→                            const q31_t * bias,
 38→                            const uint16_t pre_rshift,
 39→                            const uint16_t out_scale,
 40→                            const uint16_t post_rshift,
 41→                            q7_t * out_tensor,
 42→                            const uint16_t out_tensor_dim_x,
 43→                            const uint16_t out_tensor_dim_y,
 44→                            q15_t * in_tmp_buf,
 45→                            q7_t * tmp_buf)
 46→{
 47→#ifdef ENA_EMPTY_FUN
 48→    //empty body
 49→#elif defined(ENA_VEC_ISA) && defined(ENA_TILING)
 50→    //cache is 512KB, type is q7
 51→    uint32_t tiling_size = 256;
 52→    //num of columnar
 53→    int col_counter = 0;
 54→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
 55→    unsigned long addr_in_tmp_buf;
 56→
 57→    /*
 58→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 59→     *  im2col are done to output in q15_t format from q7_t input
 60→     */
 61→    const long align_byte = 64;
 62→    q7_t *pBuffer = (q7_t*)in_tmp_buf;
 63→    q7_t *pOut = out_tensor;
 64→    q31_t *dst_q31;
 65→#ifdef DCACHE_SIZE
 66→    int i;
 67→    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
 68→    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / 6); //sqrt(((DCACHE_SIZE) << 10) / 3 / sizeof(float16_t))
 69→    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
 70→    {
 71→        if (tiling_size_arr[i] > max_tile_size_in_cache)
 72→        {
 73→            tiling_size = tiling_size_arr[i - 1];
 74→            break;
 75→        }
 76→    }
 77→#endif
 78→#ifdef ENA_8MHVM
 79→    char *hvm_base = (char *)0x90000000;
 80→    q7_t *src2 = (q7_t *)hvm_base;
 81→    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * in_tensor_ch * ker_dim_x * ker_dim_y * out_tensor_ch;
 82→#else
 83→    q7_t *src2 = (q7_t *)in_tmp_buf
 84→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y; //matrix_A's memory space
 85→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
 86→    addr_in_tmp_buf = (unsigned long)src2;
 87→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
 88→#endif
 89→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
 90→    dst_q31 = (q31_t *)addr_in_tmp_buf;
 91→
 92→    // transpose the kernel_weight for matrix multiplication
 93→    const long row = out_tensor_ch;
 94→    const long col = ker_dim_x * ker_dim_y * in_tensor_ch;
 95→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 96→
 97→    /* This part implements the im256col function */
 98→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
 99→    {
100→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
101→        {
102→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
103→            {
104→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
105→                {
106→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
107→                    {
108→                        /* Filling 0 for out-of-bound paddings */
109→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
110→                    }
111→                    else
112→                    {
113→                        /* Copying the pixel data to column */
114→                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
115→                    }
116→                    pBuffer += in_tensor_ch;
117→                }
118→            }
119→            col_counter++;
120→
121→            /* Computation is filed for [tiling_size] columns */
122→            if (pBuffer == (q7_t*)in_tmp_buf + tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y)
123→            {
124→                pOut = nn_mat_mul_kernel_tiling_q7((q7_t *)in_tmp_buf,
125→                                                   src2,
126→                                                   dst_q31,
127→                                                   pOut,
128→                                                   col_counter,
129→                                                   in_tensor_ch * ker_dim_x * ker_dim_y,
130→                                                   out_tensor_ch,
131→                                                   pre_rshift,
132→                                                   out_scale,
133→                                                   post_rshift,
134→                                                   bias,
135→                                                   tiling_size);
136→                /* reset */
137→                col_counter = 0;
138→                pBuffer = (q7_t *)in_tmp_buf;
139→            }
140→        }
141→    }
142→
143→    /* check if there is left-over for compute */
144→    if (pBuffer != (q7_t *)in_tmp_buf)
145→    {
146→        pOut = nn_mat_mul_kernel_tiling_q7((q7_t*)in_tmp_buf,
147→                                           src2,
148→                                           dst_q31,
149→                                           pOut,
150→                                           col_counter,
151→                                           in_tensor_ch * ker_dim_x * ker_dim_y,
152→                                           out_tensor_ch,
153→                                           pre_rshift,
154→                                           out_scale,
155→                                           post_rshift,
156→                                           bias,
157→                                           tiling_size);
158→    }
159→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
160→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
161→
162→    /*
163→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
164→     *  im2col are done to output in q15_t format from q7_t input
165→     */
166→    q7_t    *pBuffer = (q7_t*)in_tmp_buf;
167→    q7_t     *pOut = out_tensor;
168→
169→    /* This part implements the im2col function */
170→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
171→    {
172→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
173→        {
174→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
175→            {
176→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
177→                {
178→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
179→                    {
180→                        /* Filling 0 for out-of-bound paddings */
181→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
182→                    }
183→                    else
184→                    {
185→                        /* Copying the pixel data to column */
186→                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
187→                    }
188→                    pBuffer += in_tensor_ch;
189→                }
190→            }
191→
192→            /* Computation is filed for every 2 columns */
193→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_y * ker_dim_x)
194→            {
195→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
196→                                                      (q7_t*)in_tmp_buf,
197→                                                      out_tensor_ch,
198→                                                      in_tensor_ch * ker_dim_y * ker_dim_x,
199→                                                      pre_rshift,
200→                                                      out_scale,
201→                                                      post_rshift,
202→                                                      bias,
203→                                                      pOut);
204→
205→                /* counter reset */
206→                pBuffer = (q7_t*)in_tmp_buf;
207→            }
208→        }
209→    }
210→
211→    /* left-over because odd number of output pixels */
212→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && (ENA_VEC_INTRINSIC)
213→    if (pBuffer != (q7_t *)in_tmp_buf)
214→    {
215→        unsigned vl;
216→        const q7_t *p_wt = ker_weight;
217→        int       i;
218→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
219→        long vlenb = NDS_VEC_CSR_GET_VLENB();
220→
221→        vl = __riscv_vsetvl_e32m1(1);
222→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
223→
224→        for (i = 0; i < out_tensor_ch; i++)
225→        {
226→            q7_t    *p_in = (q7_t*)in_tmp_buf;
227→            uint16_t colCnt2 = colCnt;
228→
229→            //clear v0~v7
230→            vl = __riscv_vsetvl_e32m8(colCnt);
231→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
232→
233→            while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
234→            {
235→                vl = __riscv_vsetvl_e8m8(colCnt2);
236→                //load src1
237→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
238→                //load src2
239→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
240→                //bump pointers and update loop counter
241→                colCnt2 -= vl;
242→                p_wt += vl;
243→                p_in += vl;
244→                //set the proper avl/SEW/LMUL values for vd4dot
245→                vl >>= 2;
246→                vl = __riscv_vsetvl_e32m8(vl);
247→                //acc += src1 * src2
248→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
249→            }
250→
251→            //extra process for the case of vd4dot's avl is not a mutiple of 4
252→            if(colCnt2 > 0)
253→            {
254→                //clean one of the dot product source
255→                vl = __riscv_vsetvlmax_e8m8();
256→                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
257→
258→                vl = __riscv_vsetvl_e8m8(colCnt2);
259→                //load src1
260→                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
261→                //load src2
262→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
263→                //bump pointers and update loop counter
264→                colCnt2 -= vl;
265→                p_wt += vl;
266→                p_in += vl;
267→                //set the proper avl/SEW/LMUL values for vd4dot
268→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
269→                vl = __riscv_vsetvl_e32m8(vl);
270→                //acc += src1 * src2
271→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
272→            }
273→
274→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
275→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
276→
277→            //add bias back
278→            vl = __riscv_vsetvl_e32m1(1);
279→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
280→            vSum = __riscv_vadd(vSum, vBias, vl);
281→
282→            vSum = __riscv_vsra(vSum, pre_rshift, vl);
283→            vSum = __riscv_vmul(vSum, out_scale, vl);
284→            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
285→
286→            //scale down, clip and store the results
287→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
288→            vl = __riscv_vsetvl_e8mf4(1);
289→            vint8mf4_t vpOut = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
290→            __riscv_vse8(pOut, vpOut, vl);
291→
292→            bias += vl;
293→            pOut += vl;
294→        }
295→    }
296→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
297→    if (pBuffer != (q7_t *)in_tmp_buf)
298→    {
299→        unsigned vl;
300→        const q7_t *p_wt = ker_weight;
301→        int       i;
302→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
303→        long vlenb = NDS_VEC_CSR_GET_VLENB();
304→
305→#if (__clang__)
306→        register const long zero asm ("x0") = 0;
307→#else
308→        register const long zero asm ("x0");
309→#endif
310→
311→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
312→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
313→
314→        for (i = 0; i < out_tensor_ch; i++)
315→        {
316→            q7_t    *p_in = (q7_t*)in_tmp_buf;
317→            uint16_t colCnt2 = colCnt;
318→
319→            //clear v0~v7
320→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
321→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
322→
323→            while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
324→            {
325→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
326→                //load src1
327→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
328→                //load src2
329→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
330→                //bump pointers and update loop counter
331→                colCnt2 -= vl;
332→                p_wt += vl;
333→                p_in += vl;
334→                //set the proper avl/SEW/LMUL values for vd4dot
335→                vl >>= 2;
336→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
337→                //acc += src1 * src2
338→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
339→            }
340→
341→            //extra process for the case of vd4dot's avl is not a mutiple of 4
342→            if(colCnt2 > 0)
343→            {
344→                //clean one of the dot product source
345→                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
346→                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
347→
348→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
349→                //load src1
350→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
351→                //load src2
352→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
353→                //bump pointers and update loop counter
354→                colCnt2 -= vl;
355→                p_wt += vl;
356→                p_in += vl;
357→                //set the proper avl/SEW/LMUL values for vd4dot
358→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
359→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
360→                //acc += src1 * src2
361→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
362→            }
363→
364→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
365→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
366→
367→            //add bias back
368→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
369→            NDS_VEC_VLW_V(NDS_VEC_V9, bias);
370→            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
371→            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
372→            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
373→            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(post_rshift));
374→
375→            //scale down, clip and store the results
376→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
377→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
378→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
379→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
380→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
381→
382→            bias += vl;
383→            pOut += vl;
384→        }
385→    }
386→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
387→    if (pBuffer != (q7_t*)in_tmp_buf)
388→    {
389→        unsigned vl;
390→        const q7_t *pA = ker_weight;
391→        int       i;
392→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
393→
394→        //set SEW for 1st time VMV_S_X
395→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
396→        vl = __riscv_vsetvl_e32m8(colCnt);
397→
398→        for (i = 0; i < out_tensor_ch; i++)
399→        {
400→            q31_t     sum = bias[i];
401→            q7_t      *pB = (q7_t*)in_tmp_buf;
402→            uint16_t colCnt2 = colCnt;
403→
404→            //init
405→            vint32m1_t vSum = __riscv_vmv_s_x_i32m1(sum, 1);
406→            //clear v8~v15
407→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
408→
409→            while (colCnt2 > 0)
410→            {
411→                vl = __riscv_vsetvl_e8m2(colCnt2);
412→                //load src1
413→                vint8m2_t vpA = __riscv_vle8_v_i8m2(pA, vl);
414→                //load src2
415→                vint8m2_t vpB = __riscv_vle8_v_i8m2(pB, vl);
416→                //acc += src1 * src2
417→                vAccumulator = __riscv_vqmacc(vAccumulator, vpB, vpA, vl);
418→                //bump pointers and update loop counter
419→                colCnt2 -= vl;
420→                pA += vl;
421→                pB += vl;
422→            }
423→
424→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
425→            vSum = __riscv_vredsum_tu(vSum, vAccumulator, vSum, vl);
426→            //move vr results to gpr
427→            sum = __riscv_vmv_x(vSum);
428→
429→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
430→            *pOut = NDS_ISA_SATS(((q31_t)sum >> post_rshift), 8);
431→            pOut++;
432→        }
433→    }
434→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
435→    if (pBuffer != (q7_t*)in_tmp_buf)
436→    {
437→        unsigned vl;
438→        const q7_t *pA = ker_weight;
439→        int       i;
440→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
441→
442→        //set SEW for 1st time VMV_S_X
443→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
444→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
445→
446→        for (i = 0; i < out_tensor_ch; i++)
447→        {
448→            q31_t     sum = bias[i];
449→            q7_t      *pB = (q7_t*)in_tmp_buf;
450→            uint16_t colCnt2 = colCnt;
451→
452→            //init
453→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
454→            //clear v8~v15
455→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
456→
457→            while (colCnt2 > 0)
458→            {
459→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
460→                //load src1
461→                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
462→                //load src2
463→                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
464→                //acc += src1 * src2
465→                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V2);
466→                //bump pointers and update loop counter
467→                colCnt2 -= vl;
468→                pA += vl;
469→                pB += vl;
470→            }
471→
472→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
473→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
474→            //move vr results to gpr
475→            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
476→
477→             sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
478→            *pOut = NDS_ISA_SATS(((q31_t)sum >> post_rshift), 8);
479→            pOut++;
480→        }
481→    }
482→#elif defined(ENA_DSP_ISA_64)
483→    if (pBuffer != (q7_t*)in_tmp_buf)
484→    {
485→        const q7_t *pA = ker_weight;
486→        int       i;
487→        for (i = 0; i < out_tensor_ch; i++)
488→        {
489→            long   sum = 0;
490→            q7_t    *pB = (q7_t*)in_tmp_buf;
491→
492→            /* basically each time it process 8 entries */
493→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 3;
494→
495→            while (colCnt)
496→            {
497→                long inA1, inB1;
498→
499→                inA1 = *__SIMD64(pA)++;
500→                inB1 = *__SIMD64(pB)++;
501→                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
502→                colCnt--;
503→            }
504→            //sum up the high and low part results (SIMD results)
505→            sum  = (q31_t)(sum >> 32) + (q31_t)sum;
506→
507→            colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x7;
508→            while (colCnt)
509→            {
510→                q7_t      inA1 = *pA++;
511→                q7_t      inB1 = *pB++;
512→                sum += inA1 * inB1;
513→                colCnt--;
514→            }
515→
516→            // add the bias back
517→            sum += bias[i];
518→
519→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
520→            *pOut = NDS_DSP_SATS(((q31_t)sum >> post_rshift), 8);
521→            pOut++;
522→        }
523→    }
524→#else
525→    if (pBuffer != (q7_t*)in_tmp_buf)
526→    {
527→        const q7_t *pA = ker_weight;
528→        int       i;
529→
530→        for (i = 0; i < out_tensor_ch; i++)
531→        {
532→            /* Load the accumulator with bias first */
533→            q31_t     sum = bias[i];
534→
535→            /* Point to the beging of the im2col buffer */
536→            q7_t    *pB = (q7_t*)in_tmp_buf;
537→
538→            /* Each time it process 4 entries */
539→            uint16_t  colCnt = in_tensor_ch * ker_dim_y * ker_dim_x >> 2;
540→
541→            while (colCnt)
542→            {
543→                long inA1, inB1;
544→
545→                inA1 = *__SIMD32(pA)++;
546→                inB1 = *__SIMD32(pB)++;
547→                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
548→                colCnt--;
549→            }
550→
551→            colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
552→            while (colCnt)
553→            {
554→                q7_t      inA1 = *pA++;
555→                q7_t      inB1 = *pB++;
556→                sum += inA1 * inB1;
557→                colCnt--;
558→            }
559→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
560→            *pOut = NDS_DSP_SATS(((q31_t)sum >> post_rshift), 8);
561→            pOut++;
562→        }
563→    }
564→#endif
565→#else
566→    uint16_t  i, j, k, l, m, n;
567→    int       conv_out;
568→    long in_row, in_col;
569→
570→    for (i = 0; i < out_tensor_ch; i++)
571→    {
572→        for (j = 0; j < out_tensor_dim_y; j++)
573→        {
574→            for (k = 0; k < out_tensor_dim_x; k++)
575→            {
576→                conv_out = bias[i];
577→                for (m = 0; m < ker_dim_y; m++)
578→                {
579→                    for (n = 0; n < ker_dim_x; n++)
580→                    {
581→                        // if-for implementation
582→                        in_row = stride_y * j + m - pad_y;
583→                        in_col = stride_x * k + n - pad_x;
584→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
585→                        {
586→                            for (l = 0; l < in_tensor_ch; l++)
587→                            {
588→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
589→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
590→                            }
591→                        }
592→                    }
593→                }
594→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
595→                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
596→            }
597→        }
598→    }
599→
600→#endif                          /* ENA_DSP_ISA */
601→}
