  1→// MM_TYPE *nn_mat_mul_kernel_tiling(const MM_TYPE * src1,
  2→//                                   const MM_TYPE * src2,
  3→//                                   MM_TYPE_VQ * tmp_out,
  4→//                                   MM_TYPE * out,
  5→//                                   const uint16_t row,
  6→//                                   const uint16_t col,
  7→//                                   const uint16_t col2,
  8→//                                   const MM_TYPE * bias,
  9→//                                   const uint16_t tiling_size)
 10→// {
 11→// #ifdef ENA_VEC_ISA
 12→#ifdef ENA_DYNAMIC_CALC_CACHE_CONFIG
 13→    unsigned int cache_size_byte = 0, tiling_size = 1;
 14→    vec_calc_tiling_size_and_cache_config(&cache_size_byte, &tiling_size);
 15→#else
 16→    //cache is 512KB
 17→    const unsigned int cache_size_byte = 512 << 10;
 18→#endif
 19→    unsigned int tiling_row_B;
 20→    //col > 8: assume max way is 8 to prevent /0
 21→    if(col < tiling_size && col > 8)
 22→    {
 23→        tiling_row_B = higher_power_2(col);
 24→    }
 25→    else
 26→    {
 27→        tiling_row_B = tiling_size;
 28→    }
 29→    /*
 30→    //4096(col2) * 1B(q7) = 4096B
 31→    //4096B / 64B(line) = 64(row offset of B)
 32→    //2048(line per way) / 64 = 32
 33→    //32 * 4(way) = 128(total num of B in cache)
 34→    //256(tiling_size) is 2 times the 128, second half 128 will cause first half 128 be all evicted
 35→    */
 36→    unsigned int min_col2_byte = cache_size_byte / (tiling_row_B >> 1);
 37→
 38→    //packing can handle just full cache
 39→    min_col2_byte = min_col2_byte >> 1;
 40→    int rvv = RVV_TILING;
 41→    unsigned int col2_byte = col2 * sizeof(MM_TYPE);   //byte of row of B
 42→
 43→    //col2 big enough
 44→    if(col2_byte >= min_col2_byte)
 45→    {
 46→        rvv = RVV_PACKING;
 47→    }
 48→
 49→    //small_matrix also use original_rvv
 50→    unsigned int total = ((row * col) + (col * col2) + (row * col2)); //ABC size
 51→    unsigned int max_size = tiling_size * tiling_size * 3; //max small_matrix size
 52→    if(total < max_size)
 53→    {
 54→        rvv = RVV_ORIGINAL;
 55→    }
 56→
 57→#ifdef ENA_PACKING_HVM
 58→    rvv = RVV_PACKING;
 59→#endif
 60→
 61→    if(rvv == RVV_ORIGINAL)
 62→    {
 63→        //original rvv
 64→        vec_mat_mul_rvv_original_vq(src1, src2, tmp_out, row, col, col2);
 65→    }
 66→    else if(rvv == RVV_TILING)
 67→    {
 68→        /* initial output */
 69→        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
 70→        //4*4 by 4*vl
 71→        vec_mat_mul_rvv_tiling_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
 72→    }
 73→    else if(rvv == RVV_PACKING)
 74→    {
 75→        /* initial output */
 76→        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
 77→        //packing_rvv
 78→        int status = vec_mat_mul_rvv_packing_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
 79→        if(status == -1)
 80→        {
 81→            return out;
 82→        }
 83→    }
 84→
 85→
 86→#ifdef CONV_BIAS
 87→#ifdef U8_U8_S8_TYPE //output is u8
 88→    //bias
 89→    int vl, avl;
 90→    for(int i = 0; i < row; i++)
 91→    {
 92→        avl = col2;
 93→        const MM_TYPE_VQ *pbias = bias;
 94→        while(avl > 0)
 95→        {
 96→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
 97→            DEF_VLOADVQ_V(NDS_VEC_V16, tmp_out);
 98→            DEF_VLOADVQ_V(NDS_VEC_V24, pbias);
 99→            NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
100→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);
101→            NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
102→            NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
103→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M4);
104→            NDS_VEC_VNCLIP_WX(NDS_VEC_V16, NDS_VEC_V16, post_rshift);
105→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
106→            NDS_VEC_VNCLIPU_WX(NDS_VEC_V16, NDS_VEC_V16, 0);
107→            NDS_VEC_VMERGE_VIM(NDS_VEC_V24, NDS_VEC_V16, 0);
108→            DEF_VSTORE_V(NDS_VEC_V24, out);
109→            tmp_out += vl;
110→            pbias += vl;
111→            out += vl;
112→            avl -= vl;
113→        }
114→    }
115→    return out;
116→#elif defined(U8_S8_S8_TYPE) || defined(S8_S8_S8_TYPE) //output is s8
117→    //bias
118→    int vl, avl;
119→    for(int i = 0; i < row; i++)
