136→            tmp_out += vl;
137→            pbias += vl;
138→            out += vl;
139→            avl -= vl;
140→        }
141→    }
142→    return out;
143→#elif defined(S8_S16_S8_TYPE) || defined(U8_S16_S8_TYPE) //output is s16
144→    //bias
145→    int vl, avl;
146→    for(int i = 0; i < row; i++)
147→    {
148→        avl = col2;
149→        const MM_TYPE_VQ *pbias = bias;
150→        while(avl > 0)
151→        {
152→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
153→            DEF_VLOADVQ_V(NDS_VEC_V0, tmp_out);
