161→            tmp_out += vl;
162→            pbias += vl;
163→            out += vl;
164→            avl -= vl;
165→        }
166→    }
167→    return out;
168→#endif
169→#else //non-bias
170→#ifdef U8_U8_S8_TYPE //output is u8
171→    int vl, avl;
172→    for(int i = 0; i < row; i++)
173→    {
174→        avl = col2;
175→        while(avl > 0)
176→        {
177→            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
178→            DEF_VLOADVQ_V(NDS_VEC_V16, tmp_out);
179→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);
