24→//// Convolution Functions
25→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
26→q7_t *nn_mat_mul_kernel_q7_bias_2sft_unroll4(const q7_t * src1,
27→                                             const q7_t * src2,
28→                                             const uint16_t out_tensor_ch,
29→                                             const uint16_t col_src1,
30→                                             const uint16_t pre_rshift,
31→                                             const uint16_t out_scale,
32→                                             const uint16_t post_rshift,
33→                                             const q31_t * bias,
34→                                             q7_t * out)
35→{
36→#if defined(ENA_NDS_V5_VEC_DOT_PROD) && (ENA_VEC_INTRINSIC)
37→    unsigned long vl;
38→    unsigned long rowCnt = out_tensor_ch >> 2;
39→    q7_t *pOut2 = out + out_tensor_ch;
40→    q7_t *pOut3 = out + out_tensor_ch * 2;
41→    q7_t *pOut4 = out + out_tensor_ch * 3;
42→
43→    const q7_t *pA = src1;
44→
45→    vl = __riscv_vsetvl_e32m1(1);
46→    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //keep zero for redsum
47→
48→    while(rowCnt > 0)
49→    {
50→        // setup pointers for A
51→        const q7_t *pA2 = pA + col_src1;
52→        const q7_t *pA3 = pA + col_src1 * 2;
53→        const q7_t *pA4 = pA + col_src1 * 3;
54→        // setup pointers for B
55→        const q7_t *pB = src2;
56→        const q7_t *pB2 = pB + col_src1;
57→        const q7_t *pB3 = pB + col_src1 * 2;
58→        const q7_t *pB4 = pB + col_src1 * 3;
59→
60→        vl = __riscv_vsetvlmax_e32m8();
61→
